INNER JOIN Sccc_Cash_Clousureline cl on cl.SCCC_CASH_CLOUSURE_id=c.SCCC_CASH_CLOUSURE_id
WHERE Sccc_Cash_Clousureline_ID = @Sccc_Cash_Clousureline_ID@

